import * as fs from 'fs/promises';
import * as path from 'path';
import { expandHome } from './shell';

export interface WrapperOptions {
    claudeBin: string;
    configDir: string;
    keychainService: string;
    outputPath: string;
}

export function renderWrapperScript(opts: Pick<WrapperOptions, 'claudeBin' | 'configDir' | 'keychainService'>): string {
    const configDir = expandHome(opts.configDir);
    return `#!/bin/zsh
# Generated by obsidian-claude-subscription. Safe to regenerate.
export CLAUDE_CONFIG_DIR=${shellQuote(configDir)}
export CLAUDE_CODE_OAUTH_TOKEN="$(/usr/bin/security find-generic-password -a "$USER" -s ${shellQuote(opts.keychainService)} -w)"
exec ${shellQuote(opts.claudeBin)} "$@"
`;
}

/**
 * Write (and chmod +x) the wrapper script to the given path. Parent dir is created if missing.
 */
export async function writeWrapperScript(opts: WrapperOptions): Promise<void> {
    const outputPath = expandHome(opts.outputPath);
    await fs.mkdir(path.dirname(outputPath), { recursive: true });
    const content = renderWrapperScript(opts);
    await fs.writeFile(outputPath, content, { mode: 0o755 });
    await fs.chmod(outputPath, 0o755);
}

function shellQuote(value: string): string {
    if (/^[A-Za-z0-9_\-./]+$/.test(value)) {
        return value;
    }
    return `"${value.replace(/\\/g, '\\\\').replace(/"/g, '\\"')}"`;
}
